query:
-- Index for filtering active/approved products (most common query)
CREATE INDEX IF NOT EXISTS idx_products_active ON products(isApproved, isActive);

-- Index for category filtering
CREATE INDEX IF NOT EXISTS idx_products_category ON products(categoryId);

-- Index for hit products sorted by hitOrder
CREATE INDEX IF NOT EXISTS idx_products_hit ON products(isHit, hitOrder);

-- Index for slug lookups (product detail page)
CREATE INDEX IF NOT EXISTS idx_products_slug ON products(slug);

-- Index for search by name/brand
CREATE INDEX IF NOT EXISTS idx_products_brand ON products(brand);

